var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"마에스트로 네퀴티아, 현 공간상에서 식별 신호가 소멸했습니다!","JPN":"マエストロ・ネキティア、現空間上での識別信号が消滅しました！","ENG":"Maestra Nequitia’s signal has extinguished in the current area!","TWN":"指揮家 莉奎蒂亞，現在空間上看不到她的識別訊號！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"메이즈 전대, 카멜롯 전대는 현재 도주한 최고 단원들을 추격 중입니다!","JPN":"メイズ戦隊、キャメロット戦隊は現在逃走した首席奏者を追っています！","ENG":"Elite Members are on the run, Maze Division and Camelot Division are currently in pursuit!","TWN":"梅茲戰隊、卡梅羅戰隊正在追擊逃逸的團員！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"*Huff… Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"후우, 해치우고 나니까 이제 좀 머리가 개운해지네. 만만치 않은 녀석이었어.","JPN":"ふう、やっつけたら頭がすっきりしたね。手ごわい相手だった。","ENG":"Ha... It feels so good now that it’s finally over. That was a rough opponent.","TWN":"呼～清理乾淨後整個清爽多了！那傢伙真不好對付！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그럴 수밖에. 네퀴티아는 그림자 중에서도 <color=#ffd34c>데모고르곤</color>으로 불리는 개체였으니까.","JPN":"当たり前だよ。ネキティアはシャドウの中でも<color=#ffd34c>デモゴルゴン</color>として呼ばれる個体だったから。","ENG":"Of course. Even amongst the Shadows, Nequitia is called the <color=#ffd34c>Demogorgon</color>.","TWN":"那是當然的囉，即便同為暗影，但莉奎蒂亞可是被歸類為<color=#ffd34c>魔神</color>呢！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"데모…… 뭐?","JPN":"デモ……なんだって？","ENG":"Demo... What?","TWN":"魔……魔什麼？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"……특별히 오래된 그림자들을 부르는 말이야. 성야의 살인마 놀이에 나오는 그림자처럼.","JPN":"……特に長く生き延びているシャドウのことだよ。聖夜の殺人鬼遊びに出てくるシャドウのようにね。","ENG":"...It’s something only the most ancient Shadows are called. Like the Shadow from the game, Killer of the Holy Night.","TWN":"……這是特別針對古老暗影的稱呼，就像聖夜的嫌疑犯遊戲裡的暗影一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 모르스 말이야?","JPN":"え？　モールスのこと？","ENG":"Oh? Are you talking about Mors?","TWN":"喔？你說莫爾斯喔？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"에이, 그거 그냥 겁 많은 신입들 놀리려고 지어낸 얘기잖아.","JPN":"いや、それって臆病な新人をビビらせようと作った話でしょ？","ENG":"Oh, come on. You just made that up to scare the newbies.","TWN":"拜託～那只是用來嚇唬膽小新人而捏造的故事吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"대외적으로는. 관리국 내부에서도 대부분은 그렇게 알고 있을 거야.","JPN":"対外的にはね。管理局の中でも大半はそうだと思っているはずだよ。","ENG":"That is the official explanation anyways. Most members of the Administration believe it too.","TWN":"那是對外的說法，管理局內部大部分也都知道這件事。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그보다 스승님, 네퀴티아는 정말 소멸한 겁니까?","JPN":"それより師匠、ネキティアは本当に消滅したんでしょうか？","ENG":"More importantly, Master, is Nequitia really dead?","TWN":"不過師父，莉奎蒂亞真的死了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"확신하기엔 아직 이르다. 핵을 파괴하는 감각이 다른 것들과 달랐어.","JPN":"確信するにはまだ早い。核を破壊したときの感じが他のシャドウとは違った。","ENG":"It’s too early to be sure. Destroying that core felt different from usual.","TWN":"現在還言之過早，破壞核心時的感覺不太一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"함교, 지금 바로……","JPN":"艦橋、今すぐ……","ENG":"Bridge, now...","TWN":"艦橋，現在立刻……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":" 음?","JPN":" うむ？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"몽타뉴? 후방으로 이송된 거 아니었어?","JPN":"モンターニュ？　後方に運ばれたんじゃなかったの？","ENG":"Montagne? Wasn’t she transferred to the rear?","TWN":"蒙塔妮？她不是已經被護送到後方嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"손에 들고 있는 그건…… 설마 카르데나스 전대장님의……","JPN":"手に持っているそれは……まさかカルデナス戦隊長の……","ENG":"In her arms... Isn't it... Commander Cardenas...","TWN":"她手裡抱著的……難道是卡特納斯戰隊長的……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"왜…… 왜 이제야 오신 거죠……?","JPN":"どうして……どうして今来たんですか……？","ENG":"Why... Why did you have to arrive now...?","TWN":"為什麼……為什麼你們現在才來……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"조금만 더 일찍 오셨어도 오빠는…… 우리 오빠는……!","JPN":"もう少し早ければ兄さんは……私の兄さんは……！","ENG":"If you had just come a little earlier, my brother... My brother would still be...!","TWN":"要是你們再快一點…… 我哥哥他就不會……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"미안하다. 하지만 우리는 더 직접적인 위협에 우선 대처할 수밖에 없다.","JPN":"悪かった。しかし、私たちはもっと間近にある脅威から対応しなければならない。","ENG":"My apologies, but we had no choice but to deal with the more direct threat first.","TWN":"我很抱歉，但我們必須優先處理更直接的威脅。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"카르데나스 전대장도…….","JPN":"カルデナス戦隊長も……","ENG":"Cardenas Commander also would have...","TWN":"我相信卡特納斯戰隊長也能明……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그런 게 뭐가 중요해!! 그 괴물에게 우리 전대원들이 전부 죽어 버렸는데!","JPN":"そんなの関係ない！！　あの化け物に戦隊員がみんな殺されてしまったのに！","ENG":"What the hell does that matter!! That monster killed everyone!","TWN":"那很重要嗎！！我們戰隊全都死於那個怪物之手！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"장렬하게 전사한 것도 아니고, 저 괴물들에게 장난감처럼 농락당하다가……!","JPN":"壮烈な戦死でもない、あの化け物におもちゃ扱いされて……！","ENG":"It was no heroic death, those monsters used them like toys and...!","TWN":"而且還不是戰死在沙場上，而是被那個怪物當作玩具一樣戲弄……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"뭐라고 말 좀 해 봐……. 제발…….","JPN":"何とか言ってよ……お願いだから……","ENG":"Say something... Please...","TWN":"為什麼不說話……說話啊……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"어째서 늦게 온 거냐고……! 당신들은 강하잖아!! 펜릴 전대는 무적이잖아!!","JPN":"どうして遅れて来たんだよ……！　あなたたちは強いだろ！！　フェンリル戦隊は無敵だろ！！","ENG":"But why were you so late...! You guys are strong!! The Fenrir Division is invincible!!","TWN":"為什麼這麼慢才出現……！你們不是很強嗎！！芬里爾戰隊不是天下無敵嗎！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아……! 아아아아!!","JPN":"あ……！　ああああ！！","ENG":"Ah...! Ahhhh!!","TWN":"啊……！啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"멈추세요, 부전대장! 아군을 공격하다니 무슨 짓입니까!","JPN":"おやめください、副戦隊長！　味方を攻撃するとは、何の真似ですか！","ENG":"Enough, Deputy Commander! What do you think you are doing, attacking your own allies?","TWN":"住手，副戰隊長！怎麼可以自己打自己人呢！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L47_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님! 괜찮아요?!","JPN":"師匠！　大丈夫ですか！？","ENG":"Master! Are you alright?!","TWN":"師父！你沒事吧？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"뭐가 무적이야!! 다 죽은 다음에 이기면 무슨 소용이냐고!!","JPN":"何が無敵だ！！　みんな死んだ後に勝って何の意味があるんだよ！！","ENG":"To hell with your invincibility!! What’s the point of winning if everyone dies!!","TWN":"什麼天下無敵！！人都死光了才出現，打贏了又有什麼用！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"너희들도 전부 죽여 버리겠어! 죽여 버릴 거야!!","JPN":"あなたたちもみんな殺す！　殺してやる！！","ENG":"I’m going to kill all of you! I will kill you all!!","TWN":"我要把你們全殺光！我要殺死你們！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"나유빈. 부전대장을 의무실로 이송해라.","JPN":"イチノセ。副戦隊長を医務室に運べ。","ENG":"Na Yubin. Get her to the infirmary.","TWN":"羅瑜斌，送副戰隊長到醫務室。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"……알겠습니다, 스승님.","JPN":"……承知しました、師匠。","ENG":"Understood, Master.","TWN":"……是，師父。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"놔!! 이거 놓으라고!! 이거 놔아아아아아!!","JPN":"離せ！！　離せと言ってるだろ！！　離せえええええ！！","ENG":"Let go!! I said let go!! Let go of me!!","TWN":"放手！放開我！！我叫你放開我！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님, 몽타뉴는 괜찮을까요?","JPN":"師匠、モンターニュは大丈夫でしょうか？","ENG":"Master, will Montagne be alright?","TWN":"師父，蒙塔妮不會有事吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"멘탈 프린팅에 의한 정신 오염이라면 부분적인 기억 소거로 완화할 수 있다.","JPN":"メンタル・プリンティングによる精神汚染なら、部分的な記憶消去で緩和できる。","ENG":"Partial memory erasure can alleviate some of the mental contamination caused by Mental Printing.","TWN":"若是因為智力複印而導致精神錯亂，還可以靠消除部分記憶來處理。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"하지만 저런 상태라면…… 시간이 해결해 주길 바랄 수밖에 없지.","JPN":"でも、あんな状態では……時間が解決してくれることを祈るしかない。","ENG":"However, in her current state... Time is her only cure.","TWN":"但以她現在的狀態……時間或許是最好的解藥。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"우으…….","JPN":"うう……","ENG":"Aww...","TWN":"嗯嗯……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"연민으로 해결될 문제가 아니다, 이수연.","JPN":"哀れみで解決する問題ではないぞ、キズナ。","ENG":"It is not a problem that can be solved with compassion, Lee Sooyeon.","TWN":"感情用事是無法解決問題的，李秀妍。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"연락이 두절됐다는 소식을 듣고 예상했던 일이었어. 지금은 눈앞의 문제에 집중할 때다.","JPN":"連絡が途切れたという知らせを聞いて予想していた。今は目の前の問題に集中するときだ。","ENG":"This was to be expected once we lost contact. We must focus on the immediate problem at hand.","TWN":"聽到聯絡不上的消息，這是可以預期的事。現在必須先專注在眼前的問題。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"함교, 지금 바로 공간 도약 반응을 확인해라.","JPN":"艦橋、今すぐ空間跳躍反応を確認しろ。","ENG":"Bridge, check for the space jump response immediately.","TWN":"艦橋，現在立刻確認空間跳躍反應！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"공간 도약 반응이요?","JPN":"空間跳躍反応ですか？","ENG":"Space jump response?","TWN":"空間跳躍反應嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어머나. 분명히 공간 도약을 통한 좌표 이탈은 차단된 상태였는데…….","JPN":"まあ。確かに空間跳躍による座標の離脱は遮断された状態だったのですが……","ENG":"My God... Coordinate escape through the space jump was supposed to be blocked...","TWN":"怎麼會這樣？剛才明明有阻擋利用空間跳躍離開座標……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"있었다는 뜻이로군.","JPN":"あったということだな。","ENG":"So there was a response.","TWN":"果然是這樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 교전 직후 검출됐어요. 너무 미약해서 센서 오류로 자동 분류돼 있었네요.","JPN":"はい。交戦直後検出されました。微弱過ぎてセンサーエラーに自動分類されていましたね。","ENG":"Yes. Right after the engagement. The response was so weak it was automatically classified as a sensor error.","TWN":"是，在交手後有偵測到，只是因為太微弱，所以自動歸類為感應器錯誤。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"계산 결과에 따르면, 현실 세계로의 직접 도약일 확률이 97퍼센트 이상입니다.","JPN":"計算結果によると、現実世界への直接跳躍である確率が97パーセント以上です。","ENG":"According to my calculations, the probability of the space jump being made to Normalside is above 97%.","TWN":"根據計算結果，直接跳躍到現實世界的機率為97%以上。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님, 갑자기 왜 그러세요?","JPN":"師匠、いきなりどうしたんですか？","ENG":"Master, what is it?","TWN":"師父，你怎麼會突然問這些？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……마에스트로다. 단원들을 산개시킨 건 우리 주의를 돌리기 위한 미끼였어.","JPN":"……マエストロだ。団員を散開したのは私たちの注意を引くための囮だった。","ENG":"...It’s Maestra. Spreading out the forces was just a decoy to lure us in.","TWN":"……是指揮家，她支開團員的目的是要轉移我們的注意力。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"No way!","TWN":"真的嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그 자식 진짜 가만 안 둬! 당장 쫓아가요, 스승님!","JPN":"あいつ、絶対に許さない！　今すぐ追いましょう、師匠！","ENG":"We can’t let her get away with this! We have to go after her, Master!","TWN":"我絕對不會放過她！立刻去追人吧，師父！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그건 어려워요. 공간 도약을 차단하고 있는 역장을 해제하려면 시간이 필요하거든요.","JPN":"それは難しいですね。空間跳躍を遮断している力場を解除するには時間がかかりますから。","ENG":"That seems quite difficult. We need time to disable the stasis field blocking the space jump.","TWN":"恐怕不容易，要解除阻擋空間跳躍的力場，會需要花一些時間。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"으으……! 끝까지 지저분한 녀석이네!","JPN":"うう……！　とこまでもずるいやつね！","ENG":"Arrrrgh...!! She just has to be so annoying to the end!","TWN":"呃……！真的是很卑鄙欸！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"함교. 당장 현실세계에 주둔 중인 전대들과 교신 연결하도록.","JPN":"艦橋。ただちに現実世界に駐屯している戦隊と交信しろ。","ENG":"Bridge. Connect us with the divisions in Normalside, immediately.","TWN":"艦橋，立刻和駐紮在現實世界的戰隊進行通訊！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"마에스트로의 예상 도착 좌표는 어디지?","JPN":"マエストロの予想到着座標はどこだ？","ENG":"What are the coordinates of Maestra’s expected arrival destination?","TWN":"指揮家預計抵達的座標在哪裡？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 예상 도착 좌표는———","JPN":"はい。予想到着座標は———","ENG":"Understood. The expected coordinates are———","TWN":"是，預計抵達的座標在———"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};